const checkpoints = [];
const boats = JSON.parse(localStorage.getItem('boats') || '[]');
const quotes = JSON.parse(localStorage.getItem('quotes') || '[]');
const plans = JSON.parse(localStorage.getItem('insurance_plans') || '[]');
const policyTypes = JSON.parse(localStorage.getItem('policy_types') || '[]');
// Find quotes whose details match the requested sailboat and ZIP/value criteria
const boatQuotes = [];
for (let i = 0; i < quotes.length; i++) {
  const q = quotes[i];
  if (q.boatType !== 'sailboat') continue;
  if (q.boatLengthFeet !== 22) continue;
  if (q.primaryZip !== '98109') continue;
  if (q.usage !== 'pleasure_personal_use_only') continue;
  if (typeof q.boatValue !== 'number' || q.boatValue < 30000 || q.boatValue > 40000) continue;
  const b = boats.find(function(bb){ return bb.id === q.boatId; });
  if (!b) continue;
  if (b.type !== 'sailboat') continue;
  if (b.lengthFeet !== 22) continue;
  if (b.primaryZip !== '98109') continue;
  boatQuotes.push({ quote: q, boat: b });
}
// CP1: User has a quote whose boat details match a 22 ft sailboat in 98109 with value around 35k
const cp1Passed = boatQuotes.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.25 });
// Attach selected plan to those quotes
const boatQuotesWithPlan = boatQuotes.map(function(item){
  const p = plans.find(function(pl){ return pl.id === item.quote.selectedPlanId; }) || null;
  return { quote: item.quote, boat: item.boat, plan: p };
});
// Filter to quotes where both quote and plan have 300k liability and $500 deductible
const candidateQuotes = boatQuotesWithPlan.filter(function(item){
  const q = item.quote; const p = item.plan;
  return !!p && q.liabilityLimit === 300000 && q.deductible === 500 && p.liabilityLimit === 300000 && p.deductible === 500;
});
// CP2: Among matching boat quotes, user selected a plan that actually has 300k liability and $500 deductible
const cp2Passed = candidateQuotes.length > 0;
checkpoints.push({ passed: cp2Passed, weight: 0.35 });
// Determine the cheapest available-online plan with 300k / 500 limits
const matchingPlans = plans.filter(function(p){ return p.isAvailableOnline && p.liabilityLimit === 300000 && p.deductible === 500; });
let cheapestMonthly = null;
for (let i = 0; i < matchingPlans.length; i++) {
  const price = typeof matchingPlans[i].basePriceMonthly === 'number' ? matchingPlans[i].basePriceMonthly : 0;
  if (cheapestMonthly === null || price < cheapestMonthly) {
    cheapestMonthly = price;
  }
}
const cheapestPlanIds = matchingPlans.filter(function(p){
  const price = typeof p.basePriceMonthly === 'number' ? p.basePriceMonthly : 0;
  return cheapestMonthly !== null && price === cheapestMonthly;
}).map(function(p){ return p.id; });
// CP3: Selected plan is the cheapest among all online plans with 300k liability and $500 deductible
const cp3Passed = candidateQuotes.some(function(item){ return cheapestPlanIds.indexOf(item.plan.id) !== -1; });
checkpoints.push({ passed: cp3Passed, weight: 0.25 });
// CP4: For a quote on that cheapest plan, billing frequency is set to annual
const cp4Passed = candidateQuotes.some(function(item){
  return cheapestPlanIds.indexOf(item.plan.id) !== -1 && item.quote.billingFrequency === 'annually';
});
checkpoints.push({ passed: cp4Passed, weight: 0.15 });
return checkpoints.reduce(function(sum, cp){ return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];
const quotes = JSON.parse(localStorage.getItem('quotes') || '[]');
const boats = JSON.parse(localStorage.getItem('boats') || '[]');
const optionalCoverages = JSON.parse(localStorage.getItem('optional_coverages') || '[]');
const quoteOptionalCoverages = JSON.parse(localStorage.getItem('quote_optional_coverages') || '[]');
const plans = JSON.parse(localStorage.getItem('insurance_plans') || '[]');
// Motorboat quotes for 98109, pleasure use
const motorQuotes = quotes.filter(function(q){
  if (q.boatType !== 'motorboat') return false;
  if (q.primaryZip !== '98109') return false;
  if (q.usage !== 'pleasure_personal_use_only') return false;
  if (!q.boatValue || q.boatValue <= 0) return false;
  return true;
});
// Determine the mid-priced plan among online plans with 300k liability and 1000 deductible
const sameLimitPlans = plans.filter(function(p){ return p.isAvailableOnline && p.liabilityLimit === 300000 && p.deductible === 1000; });
sameLimitPlans.sort(function(a, b){
  const pa = typeof a.basePriceMonthly === 'number' ? a.basePriceMonthly : 0;
  const pb = typeof b.basePriceMonthly === 'number' ? b.basePriceMonthly : 0;
  return pa - pb;
});
let midPlanId = null;
if (sameLimitPlans.length > 0) {
  const midIndex = Math.floor((sameLimitPlans.length - 1) / 2);
  midPlanId = sameLimitPlans[midIndex].id;
}
// Quotes that selected the mid-priced plan
const midPlanQuotes = motorQuotes.filter(function(q){ return midPlanId && q.selectedPlanId === midPlanId; });
// CP1: User has a recreational motorboat quote in 98109 that selected the mid-priced 300k/1000 plan
const cp1Passed = midPlanQuotes.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });
// Look up towing and personal effects optional coverages
const ocTowing = optionalCoverages.find(function(oc){ return oc.code === 'towing_assistance'; }) || null;
const ocPE = optionalCoverages.find(function(oc){ return oc.code === 'personal_effects'; }) || null;
// Among those quotes, find ones with towing enabled and personal effects >= $1,000
const quotesWithRequiredOptions = midPlanQuotes.filter(function(q){
  const qocsForQuote = quoteOptionalCoverages.filter(function(qoc){ return qoc.quoteId === q.id && qoc.selected; });
  const towId = ocTowing ? ocTowing.id : null;
  const peId = ocPE ? ocPE.id : null;
  const qocTowing = towId ? qocsForQuote.find(function(x){ return x.optionalCoverageId === towId && x.selected; }) : null;
  const qocPE = peId ? qocsForQuote.find(function(x){ return x.optionalCoverageId === peId && x.selected; }) : null;
  const hasTowing = !!qocTowing;
  const hasPE = !!qocPE && typeof qocPE.selectedLimit === 'number' && qocPE.selectedLimit >= 1000;
  return hasTowing && hasPE;
});
// CP2: On that mid-priced plan, towing and personal effects (>= $1,000) are both enabled for at least one quote
const cp2Passed = quotesWithRequiredOptions.length > 0;
checkpoints.push({ passed: cp2Passed, weight: 0.35 });
// CP3: For such a quote, total additional monthly cost for optional coverages is <= $20
const cp3Passed = quotesWithRequiredOptions.some(function(q){
  return typeof q.optionalCoveragesTotalMonthly === 'number' && q.optionalCoveragesTotalMonthly <= 20;
});
checkpoints.push({ passed: cp3Passed, weight: 0.25 });
return checkoints.reduce ? checkpoints.reduce(function(sum, cp){ return sum + (cp.passed ? cp.weight : 0); }, 0) : 0;

const checkpoints = [];
