const policies = JSON.parse(localStorage.getItem('policies') || '[]');
const boats = JSON.parse(localStorage.getItem('boats') || '[]');
const policyDocuments = JSON.parse(localStorage.getItem('policy_documents') || '[]');
let viewedIdCard = null;
try { viewedIdCard = JSON.parse(localStorage.getItem('task3_lastViewedIdCard') || 'null'); } catch (e) { viewedIdCard = null; }
// Identify the active policy for a 20 ft motorboat in ZIP 98109
let targetPolicy = null;
for (let i = 0; i < policies.length; i++) {
  const p = policies[i];
  if (p.status !== 'active') continue;
  if (p.primaryZip !== '98109') continue;
  const b = boats.find(function(bo){ return bo.id === p.boatId; });
  if (!b) continue;
  if (b.type !== 'motorboat') continue;
  if (b.lengthFeet !== 20) continue;
  targetPolicy = p;
  break;
}
// CP1: User is logged in as demo_user
const cp1Passed = username === 'demo_user';
checkpoints.push({ passed: cp1Passed, weight: 0.25 });
// CP2: That target policy's mailing address was updated to the specified Seattle address in ZIP 98109
let cp2Passed = false;
if (targetPolicy) {
  cp2Passed = targetPolicy.mailingAddressLine1 === '123 Marina Way' && targetPolicy.mailingCity === 'Seattle' && targetPolicy.mailingState === 'WA' && targetPolicy.mailingZip === '98109';
}
checkpoints.push({ passed: cp2Passed, weight: 0.35 });
// CP3: The last viewed ID card matches the current ID card document for the same policy
let cp3Passed = false;
if (targetPolicy && viewedIdCard && viewedIdCard.policyId === targetPolicy.id) {
  const doc = policyDocuments.find(function(d){ return d.id === viewedIdCard.documentId; });
  if (doc && doc.policyId === targetPolicy.id && doc.type === 'id_card' && !!doc.isCurrent) {
    cp3Passed = true;
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.4 });
return checkpoints.reduce(function(sum, cp){ return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];
const claims = JSON.parse(localStorage.getItem('claims') || '[]');
const policies = JSON.parse(localStorage.getItem('policies') || '[]');
const boats = JSON.parse(localStorage.getItem('boats') || '[]');
// Locate the active policy for a 20 ft motorboat in ZIP 98109
let targetPolicy = null;
for (let i = 0; i < policies.length; i++) {
  const p = policies[i];
  if (p.status !== 'active') continue;
  if (p.primaryZip !== '98109') continue;
  const b = boats.find(function(bo){ return bo.id === p.boatId; });
  if (!b) continue;
  if (b.type !== 'motorboat') continue;
  if (b.lengthFeet !== 20) continue;
  targetPolicy = p;
  break;
}
// Claims that match policy, type, status, and main incident details
let matchingClaimsBasic = [];
if (targetPolicy) {
  matchingClaimsBasic = claims.filter(function(c){
    if (c.policyId !== targetPolicy.id) return false;
    if (c.claimType !== 'boat_insurance') return false;
    if (c.status !== 'submitted') return false;
    if (!c.incidentDate || String(c.incidentDate).indexOf('2025-08-15') !== 0) return false;
    if (!c.incidentLocation || c.incidentLocation.toLowerCase().indexOf('lake union') === -1) return false;
    if (c.causeOfDamage !== 'collision_with_dock') return false;
    if (c.injuriesStatus !== 'no_injuries') return false;
    if (!(c.policeReportStatus === 'no' || c.policeReportStatus === 'not_reported')) return false;
    return true;
  });
}
// Narrow to those also having the exact damage amount and owner details
const matchingClaimsFull = matchingClaimsBasic.filter(function(c){
  if (c.estimatedDamageAmount !== 3200) return false;
  if (c.ownerFirstName !== 'Alex') return false;
  if (c.ownerLastName !== 'Rivera') return false;
  if (c.ownerPhone !== '2065550199') return false;
  if (c.ownerEmail !== 'alex.rivera@example.com') return false;
  return true;
});
// CP1: There is a submitted boat claim on the correct policy with the specified Lake Union collision details, date, injury, and police report status
const cp1Passed = matchingClaimsBasic.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });
// CP2: That claim also has the exact $3,200 damage amount and the correct owner contact information
const cp2Passed = matchingClaimsFull.length > 0;
checkpoints.push({ passed: cp2Passed, weight: 0.6 });
return checkpoints.reduce(function(sum, cp){ return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];
const agents = JSON.parse(localStorage.getItem('agents') || '[]');
const requests = JSON.parse(localStorage.getItem('agent_consultation_requests') || '[]');
const activeAgents = agents.filter(function(a){ return a && a.isActive; });
// Determine the 'nearest' agent in ZIP 98109 based on array order
const nearest98109Agent = activeAgents.find(function(a){ return a.officeZip === '98109'; }) || null;
// Requests that go to an active agent in 98109 with the correct name/email and message content
const relevantRequests = requests.filter(function(r){
  const ag = activeAgents.find(function(a){ return a.id === r.agentId; });
  if (!ag) return false;
  if (ag.officeZip !== '98109') return false;
  if (r.fromName !== 'Jordan Lee') return false;
  if (!r.fromEmail || r.fromEmail.toLowerCase() !== 'jordan.lee@example.com') return false;
  const msg = (r.message || '').toLowerCase();
  if (msg.indexOf('boat insurance') === -1) return false;
  if (msg.indexOf('22-foot') === -1 && msg.indexOf('22 ft') === -1 && msg.indexOf('22ft') === -1) return false;
  if (msg.indexOf('98109') === -1) return false;
  return true;
});
// CP1: User sent at least one consultation request to an active agent in ZIP 98109 with the correct identity and message content
const cp1Passed = relevantRequests.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.6 });
// CP2: At least one such request was sent specifically to the nearest agent (first active agent in 98109)
let cp2Passed = false;
if (nearest98109Agent) {
  cp2Passed = relevantRequests.some(function(r){ return r.agentId === nearest98109Agent.id; });
}
checkpoints.push({ passed: cp2Passed, weight: 0.4 });
return checkpoints.reduce(function(sum, cp){ return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];
const policyTypes = JSON.parse(localStorage.getItem('policy_types') || '[]');
const quotes = JSON.parse(localStorage.getItem('quotes') || '[]');
const boats = JSON.parse(localStorage.getItem('boats') || '[]');
const plans = JSON.parse(localStorage.getItem('insurance_plans') || '[]');
// Policy types that include both on-water towing and uninsured boater coverage
const featurefulTypes = policyTypes.filter(function(pt){ return pt.isActive && pt.includesOnWaterTowing && pt.includesUninsuredBoaterCoverage; });
const featurefulTypeIds = featurefulTypes.map(function(pt){ return pt.id; });
// Quotes using any featureful policy type, with required boat value, ZIP, and liability >= 500k
const featurefulQuotes = quotes.filter(function(q){
  if (featurefulTypeIds.indexOf(q.policyTypeId) === -1) return false;
  if (q.primaryZip !== '98109') return false;
  if (q.boatValue !== 35000) return false;
  if (q.liabilityLimit < 500000) return false;
  const b = boats.find(function(bo){ return bo.id === q.boatId; });
  if (!b) return false;
  if (b.value !== 35000) return false;
  if (b.primaryZip !== '98109') return false;
  return true;
});
// CP1: User has at least one quote on a policy type that includes towing and uninsured boater coverage, with 500k+ liability for a 35k boat in 98109
const cp1Passed = featurefulQuotes.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });
// Determine the least expensive policy type among those with both features (by relativePriceRank)
let cheapestType = null;
for (let i = 0; i < featurefulTypes.length; i++) {
  const pt = featurefulTypes[i];
  if (!cheapestType || pt.relativePriceRank < cheapestType.relativePriceRank) {
    cheapestType = pt;
  }
}
const cheapestTypeId = cheapestType ? cheapestType.id : null;
// Quotes that both satisfy the above and use the cheapest qualifying policy type
const cheapestTypeQuotes = featurefulQuotes.filter(function(q){ return cheapestTypeId && q.policyTypeId === cheapestTypeId; });
// CP2: At least one such quote uses the least expensive policy type that includes both towing and uninsured boater coverage
const cp2Passed = cheapestTypeQuotes.length > 0;
checkpoints.push({ passed: cp2Passed, weight: 0.3 });
// CP3: For a quote on that cheapest policy type, a plan was selected and the chosen liability limit is allowed for that type
const cp3Passed = cheapestTypeQuotes.some(function(q){
  if (!q.selectedPlanId) return false;
  const pt = policyTypes.find(function(p){ return p.id === q.policyTypeId; });
  if (!pt || !Array.isArray(pt.allowedLiabilityLimits)) return false;
  if (pt.allowedLiabilityLimits.indexOf(q.liabilityLimit) === -1) return false;
  const plan = plans.find(function(p){ return p.id === q.selectedPlanId; });
  if (!plan) return false;
  if (plan.policyTypeId !== q.policyTypeId) return false;
  return true;
});
checkpoints.push({ passed: cp3Passed, weight: 0.3 });
return checkpoints.reduce(function(sum, cp){ return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];
const quotes = JSON.parse(localStorage.getItem('quotes') || '[]');
const discounts = JSON.parse(localStorage.getItem('discounts') || '[]');
// Find the quote saved with the specified label
const targetQuote = quotes.find(function(q){ return q.label === 'Safety + Multi-Policy Discounts'; }) || null;
const safetyDisc = discounts.find(function(d){ return d.code === 'boating_safety_course' && d.isActive; }) || null;
const multiDisc = discounts.find(function(d){ return d.code === 'multi_policy' && d.isActive; }) || null;
// CP1: Quote with this label exists, for a 25k boat in 98109 with reasonable boat details
let cp1Passed = false;
if (targetQuote) {
  const valOk = typeof targetQuote.boatValue === 'number' && targetQuote.boatValue >= 20000 && targetQuote.boatValue <= 30000;
  const zipOk = targetQuote.primaryZip === '98109';
  const lenOk = typeof targetQuote.boatLengthFeet === 'number' && targetQuote.boatLengthFeet > 0;
  cp1Passed = valOk && zipOk && lenOk;
}
checkpoints.push({ passed: cp1Passed, weight: 0.4 });
// CP2: Both Boating Safety Course and Multi-Policy discounts are applied to this quote
let cp2Passed = false;
if (targetQuote && Array.isArray(targetQuote.appliedDiscountIds) && safetyDisc && multiDisc) {
  const hasSafety = targetQuote.appliedDiscountIds.indexOf(safetyDisc.id) !== -1;
  const hasMulti = targetQuote.appliedDiscountIds.indexOf(multiDisc.id) !== -1;
  cp2Passed = hasSafety && hasMulti;
}
checkpoints.push({ passed: cp2Passed, weight: 0.3 });
// CP3: Billing frequency is monthly
const cp3Passed = !!(targetQuote && targetQuote.billingFrequency === 'monthly');
checkpoints.push({ passed: cp3Passed, weight: 0.2 });
// CP4: Quote is actually saved and has a reference number
const cp4Passed = !!(targetQuote && targetQuote.status === 'saved' && !!targetQuote.referenceNumber);
checkpoints.push({ passed: cp4Passed, weight: 0.1 });
return checkpoints.reduce(function(sum, cp){ return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];
const helpArticles = JSON.parse(localStorage.getItem('help_articles') || '[]');
const quotes = JSON.parse(localStorage.getItem('quotes') || '[]');
const boats = JSON.parse(localStorage.getItem('boats') || '[]');
// Compute max online boat length from eligibility articles (same logic as BusinessLogic)
let maxLen = null;
for (let i = 0; i < helpArticles.length; i++) {
  const a = helpArticles[i];
  const slugOk = a.slug === 'boat_eligibility_for_online_quotes' || a.slug === 'faq_maximum_boat_length';
  if (!slugOk || !a.isPublished || typeof a.maxOnlineQuoteBoatLengthFeet !== 'number') continue;
  if (maxLen === null || a.maxOnlineQuoteBoatLengthFeet < maxLen) {
    maxLen = a.maxOnlineQuoteBoatLengthFeet;
  }
}
if (maxLen === null) { maxLen = 40; }
const targetLen = maxLen - 1;
// Quotes for a motorboat in 98109 valued at 25k with length exactly max-1
const candidateQuotes = quotes.filter(function(q){
  if (q.boatType !== 'motorboat') return false;
  if (q.primaryZip !== '98109') return false;
  if (q.boatValue !== 25000) return false;
  if (q.boatLengthFeet !== targetLen) return false;
  if (q.usage !== 'pleasure_personal_use_only') return false;
  return true;
});
// CP1: At least one quote has motorboat details with length exactly 1 ft less than the max online length, value 25k, ZIP 98109
const cp1Passed = candidateQuotes.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.6 });
// CP2: For such a quote, the underlying boat record also reflects the same type, length, value, and ZIP (indicating a fully valid boat-details step)
const cp2Passed = candidateQuotes.some(function(q){
  const b = boats.find(function(bo){ return bo.id === q.boatId; });
  if (!b) return false;
  if (b.type !== 'motorboat') return false;
  if (b.lengthFeet !== targetLen) return false;
  if (b.value !== 25000) return false;
  if (b.primaryZip !== '98109') return false;
  return true;
});
checkpoints.push({ passed: cp2Passed, weight: 0.4 });
return checkpoints.reduce(function(sum, cp){ return sum + (cp.passed ? cp.weight : 0); }, 0);
